import React from "react";
import { Box, Typography, LinearProgress } from "@mui/material";
import processingLoader from "../loadertest/D_parsing_loader.gif";

interface ProcessingLoaderProps {
  open: boolean;
}

const ProcessingLoader: React.FC<ProcessingLoaderProps> = ({ open }) => {
  if (!open) return null;
console.log(processingLoader);
  return (
    <Box
      sx={{
        position: "fixed",
        inset: 0,
        zIndex: 99999,
        bgcolor: "#ffffff",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
      }}
    >
      <Box
        sx={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          animation: "fadeIn 0.3s ease-in-out",
          "@keyframes fadeIn": {
            from: {
              opacity: 0,
              transform: "translateY(10px)",
            },
            to: {
              opacity: 1,
              transform: "translateY(0)",
            },
          },
        }}
      >
        <Box
          component="img"
          src={processingLoader}
          alt="Processing"
          sx={{
            width: 210,
            height: 210,
            objectFit: "contain",
            userSelect: "none",
            pointerEvents: "none",
          }}
        />

        <Typography
          variant="h6"
          sx={{
            mt: 2,
            fontWeight: 700,
            color: "#1e293b",
          }}
        >
          Processing Email
        </Typography>

        <Typography
          variant="body2"
          sx={{
            mt: 1,
            mb: 3,
            color: "#64748b",
            textAlign: "center",
          }}
        >
          Sending data to BookingBuilder®...
        </Typography>

        <LinearProgress
          sx={{
            width: 220,
            height: 6,
            borderRadius: 999,
            bgcolor: "#e2e8f0",
            "& .MuiLinearProgress-bar": {
              backgroundColor: "#6aa2ba",
              borderRadius: 999,
            },
          }}
        />
      </Box>
    </Box>
  );
};

export default ProcessingLoader;